const fields = $('Receive Lead Form').first().json.body.data.fields;
const getField = (label) => {
  const field = fields.find(f => f.label === label);
  if (!field) return '';
  if (field.type === 'DROPDOWN' && field.options) {
    const values = Array.isArray(field.value) ? field.value : [field.value];
    const selected = field.options.find(o => values.includes(o.id));
    return selected ? selected.text : '';
  }
  return field.value ?? '';
};
return [{
  json: {
    name: getField('Full Name'),
    email: getField('Email'),
    phone: getField('Phone'),
    business_type: getField('Business Type'),
    business_name: getField('Business Name'),
    challenge: getField('What is your biggest business challenge?'),
    how_heard: getField('How did you hear about us?'),
    submitted_at: $('Receive Lead Form').first().json.body.createdAt,
    client_id: $('Get Client Config').first().json.client_id,
    notify_email: $('Get Client Config').first().json.notify_email,
    sheet_id: $('Get Client Config').first().json.sheet_id,
    from_name: $('Get Client Config').first().json.from_name,
    from_email: $('Get Client Config').first().json.from_email,
  }
}];

// Claude returns: data.content[0].text
const raw = $input.first().json.content[0].text;
const lead = $('Extract Lead Data').first().json;

// Capture token usage for logging
const usage = $input.first().json.usage || {};
const tokensIn = usage.input_tokens || 0;
const tokensOut = usage.output_tokens || 0;
// claude-sonnet-4 pricing: $3/M input, $15/M output
const costEstimate = ((tokensIn / 1000000) * 3) + ((tokensOut / 1000000) * 15);

const from_name = $('Extract Lead Data').first().json.from_name;

let parsed;
try {
  const cleaned = raw.replace(/```json|```/g, '').trim();
  parsed = JSON.parse(cleaned);
} catch(e) {
  parsed = {
    score: 5,
    score_reason: 'Could not parse AI response',
    email_subject: 'Thanks for reaching out to CAIAC Digital',
    email_body: `Hi ${lead.name},\n\nThank you for your interest in CAIAC Digital. We would love to learn more about how we can help ${lead.business_name}.\n\nCould we schedule a quick 15-minute call this week?\n\nBest,\nChad Wallace\nCAIAC Digital`
  };
}

const email_body = parsed.email_body + "\n\n---\nThis message was generated by AI on behalf of " + from_name + ". A team member will follow up with you personally.";

return [{
  json: {
    ...lead,
    score: parsed.score,
    score_reason: parsed.score_reason,
    email_subject: parsed.email_subject,
    email_body: email_body,
    tokens_in: tokensIn,
    tokens_out: tokensOut,
    cost_estimate: costEstimate,
    client_id: $('Extract Lead Data').first().json.client_id,
    notify_email: $('Extract Lead Data').first().json.notify_email,
    sheet_id: $('Extract Lead Data').first().json.sheet_id,
    from_name: $('Extract Lead Data').first().json.from_name,
    from_email: $('Extract Lead Data').first().json.from_email,
  }
}];

// Log AI usage to Postgres via n8n Postgres node
// This node passes structured data to the next Postgres node
const lead = $('Parse AI Response').first().json;

return [{
  json: {
    client_id: $('Parse AI Response').first().json.client_id,
    workflow: 'lead_capture',
    tokens_in: lead.tokens_in || 0,
    tokens_out: lead.tokens_out || 0,
    cost_estimate: lead.cost_estimate || 0
  }
}];
